import { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const API  = "https://team-task-manager-4-7vl7.onrender.com";

export default function Projects() {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [error, setError] = useState('');
 const token = localStorage.getItem("token") || "";
  const navigate = useNavigate();

  const handleCreate = async (e) => {
    e.preventDefault();
    console.log("API:", API);
  console.log("TOKEN:", token);
    try {
      await axios.post(`${API}/api/projects`,
        { name, description },
        { headers: { Authorization: `Bearer ${token}` }}
      );
      useEffect(() => {
  fetchProjects();
}, []);
    } catch (err) {
      setError(err.response?.data?.message || 'Error!');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>📁 Create Project</h2>
        {error && <p style={styles.error}>{error}</p>}
        <form onSubmit={handleCreate}>
          <input style={styles.input}
            type="text" placeholder="Project Name"
            value={name}
            onChange={e => setName(e.target.value)}
            required />
          <textarea style={styles.input}
            placeholder="Description"
            value={description}
            onChange={e => setDescription(e.target.value)}
            rows={3} />
          <button style={styles.btn} type="submit">
            Create Project
          </button>
        </form>
        <button style={styles.back}
          onClick={() => navigate('/dashboard')}>
          ← Back to Dashboard
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: { display:'flex', justifyContent:'center',
    alignItems:'center', minHeight:'100vh',
    background:'#0A2342' },
  card: { background:'white', padding:40, borderRadius:12,
    width:400, boxShadow:'0 10px 30px rgba(0,0,0,0.3)' },
  title: { textAlign:'center', color:'#0A2342' },
  input: { width:'100%', padding:12, margin:'8px 0',
    borderRadius:8, border:'1px solid #ddd', fontSize:14,
    boxSizing:'border-box' },
  btn: { width:'100%', padding:12, background:'#27AE60',
    color:'white', border:'none', borderRadius:8,
    fontSize:16, cursor:'pointer', marginTop:10 },
  back: { width:'100%', padding:10, background:'transparent',
    color:'#0A2342', border:'1px solid #0A2342',
    borderRadius:8, fontSize:14, cursor:'pointer',
    marginTop:10 },
  error: { color:'red', textAlign:'center' }
};
